export function formatNumberFixed(
  value: number,
  fractionDigits: number
): string {
  const threshold = 10 ** -fractionDigits;

  if (value > 0 && value < threshold) {
    return `<${threshold.toFixed(fractionDigits)}`;
  }

  if (value < 0 && Math.abs(value) < threshold) {
    return `>-${threshold.toFixed(fractionDigits)}`;
  }

  return value.toLocaleString(undefined, {
    minimumFractionDigits: fractionDigits,
    maximumFractionDigits: fractionDigits,
  });
}

export function formatNumberRoundedDown(
  value: number,
  fractionDigits: number
): string {
  const factor = 10 ** fractionDigits;
  const sign = value < 0 ? "-" : "";
  const roundedDown = Math.floor(Math.abs(value) * factor) / factor;
  return `${sign}${roundedDown.toLocaleString(undefined, {
    minimumFractionDigits: fractionDigits,
    maximumFractionDigits: fractionDigits,
  })}`;
}

export function formatCurrencyFixed(value: number, fractionDigits = 2): string {
  const threshold = 10 ** -fractionDigits;

  if (value > 0 && value < threshold) {
    return `<$${threshold.toFixed(fractionDigits)}`;
  }

  if (value < 0 && Math.abs(value) < threshold) {
    return `>-$${threshold.toFixed(fractionDigits)}`;
  }

  return `$${value.toLocaleString(undefined, {
    minimumFractionDigits: fractionDigits,
    maximumFractionDigits: fractionDigits,
  })}`;
}
